260	                                      const hybrid_state_v1& state,
261	                                      pid_t child_pid = -1)
262	{
263	  spdlog::info("hybrid handback: connecting to gdbstub on tcp::{}", port);
264	  const int fd = detail::connect_loopback(port, std::chrono::seconds(5),
265	                                          child_pid);
266	  spdlog::info("hybrid handback: connected, discovering register map");
267	  gdbstub::Session sess{fd};
268	
269	  const auto reg_map = detail::discover_reg_map(sess);
270	  spdlog::info("hybrid handback: {} registers advertised, restoring state",
271	               reg_map.size());
272	
273	  // RV64 core: x0..x31 = 0..31, pc = 32. Hard-coded because the core
274	  // feature is always first.
275	  for (unsigned i = 1; i < 32; ++i) {
276	    auto reply = sess.send_command(gdbstub::encode_p_body(i, state.gpr[i]));
