#ifndef SYS_CALL_HPP
#define SYS_CALL_HPP

#include "picolib.hpp"

#include <fcntl.h>
#include <spdlog/spdlog.h>
#include <sys/stat.h>
#include <sys/time.h>
#include <unistd.h>

#include <cerrno>
#include <cstdint>
#include <cstring>

#include <algorithm>
#include <vector>

uint64_t handle_gettimeofday(uint64_t a0 __attribute__((unused)),
                             uint64_t a1 __attribute__((unused)),
                             uint64_t a2 __attribute__((unused)),
                             uint64_t a3 __attribute__((unused)),
                             uint64_t a4 __attribute__((unused)),
                             uint64_t a5 __attribute__((unused)),
                             uint64_t a6 __attribute__((unused)))
{
  struct timeval tv;
  struct timezone tz;
  int ret = gettimeofday(&tv, &tz);
  if (ret == -1) {
    spdlog::error("sys_call: gettimeofday failed: {}", std::strerror(errno));
    return -1;
  }

  void* target_tv =
    (data_region.data.data() + (a0 - data_region.region.base_address));

  if (riscv_xlen == 32) {
    ((struct timeval_32*) target_tv)->tv_sec = (uint32_t) tv.tv_sec;
    ((struct timeval_32*) target_tv)->tv_usec = (uint32_t) tv.tv_usec;
  } else {
    ((struct timeval_64*) target_tv)->tv_sec = tv.tv_sec;
    ((struct timeval_64*) target_tv)->tv_usec = tv.tv_usec;
  }

  return 0;
};

uint64_t handle_open(uint64_t a0 __attribute__((unused)),
                     uint64_t a1 __attribute__((unused)),
                     uint64_t a2 __attribute__((unused)),
                     uint64_t a3 __attribute__((unused)),
                     uint64_t a4 __attribute__((unused)),
                     uint64_t a5 __attribute__((unused)),
                     uint64_t a6 __attribute__((unused)))
{
  char name[100];
  auto iter = data_region.data.begin() + a0;
  int i = 0;
  while (*iter && i < 100) {
    name[i] = *iter;
    ++iter;
    ++i;
  }
  name[i] = '\0';

  int fd = open(name, a1, a2);
  if (fd == -1) {
    spdlog::error(
      "sys_call: open failed: file='{}', flags={:#x}, mode={:#o}: {}", name, a1,
      a2, std::strerror(errno));
  }
  return fd;
};

uint64_t handle_lseek(uint64_t a0 __attribute__((unused)),
                      uint64_t a1 __attribute__((unused)),
                      uint64_t a2 __attribute__((unused)),
                      uint64_t a3 __attribute__((unused)),
                      uint64_t a4 __attribute__((unused)),
                      uint64_t a5 __attribute__((unused)),
                      uint64_t a6 __attribute__((unused)))
{
  off_t ret = lseek(a0, a1, a2);
  if (ret == -1) {
    spdlog::error("sys_call: lseek failed: fd={}, offset={}, whence={}: {}", a0,
                  a1, a2, std::strerror(errno));
  }
  return ret;
};

